#pragma once

enum vga_mode
{
    VGA_MODE_640x480,
    VGA_MODE_640x400
};

#ifdef __cplusplus
extern "C" {
#endif

void *init_vga(enum vga_mode);

#ifdef __cplusplus
}
#endif

